+import { DynamoDBToolboxError } from '~/errors/index.js'
+import type { ItemSchema, MapSchema } from '~/schema/types/index.js'
+
+/**
+ * Validates sibling-based requiredness after defaults and links have been applied.
+ */
+export const validateRequiredIf = (
+  schema: ItemSchema | MapSchema,
+  value: Record<string, unknown>,
+  path?: string
+): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always' || value[attributeName] !== undefined) continue
+
+    for (const requirement of attribute.props.requiredIf ?? []) {
+      const controllingValue = value[requirement.attributeName]
+      if (controllingValue !== undefined && requirement.values.includes(controllingValue)) {
+        const dependentPath = [path, attributeName].filter(Boolean).join('.')
+        throw new DynamoDBToolboxError('parsing.requiredIf', {
+          message: `Attribute '${dependentPath}' is required when sibling '${requirement.attributeName}' is one of the configured values.`,
+          path: dependentPath || undefined,
+          payload: { attributeName, requirement, value }
+        })
+      }
+    }
+  }
+}
